import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.BYehg5q7.js";const p=JSON.parse('{"title":"Trend Alerts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/trend-alerts.md","filePath":"guide/trend-alerts.md","lastUpdated":1772287587000}'),n={name:"guide/trend-alerts.md"};function o(i,e,d,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="trend-alerts" tabindex="-1">Trend Alerts <a class="header-anchor" href="#trend-alerts" aria-label="Permalink to &quot;Trend Alerts&quot;">​</a></h1><p>The Trends &amp; Alerts section on the dashboard automatically scans your lab history and surfaces patterns worth paying attention to. You do not need to configure anything — it runs every time you load or update your data.</p><h2 id="two-detection-methods" tabindex="-1">Two Detection Methods <a class="header-anchor" href="#two-detection-methods" aria-label="Permalink to &quot;Two Detection Methods&quot;">​</a></h2><p>getbased uses two independent methods to detect problems:</p><h3 id="_1-sudden-change" tabindex="-1">1. Sudden Change <a class="header-anchor" href="#_1-sudden-change" aria-label="Permalink to &quot;1. Sudden Change&quot;">​</a></h3><p>Compares your most recent result to the one before it. If the jump is larger than 25% of the reference range width <strong>and</strong> the latest value is outside the normal range, it raises a sudden change alert.</p><p>This catches acute shifts — a result that moved significantly from the previous draw.</p><h3 id="_2-linear-regression-trend" tabindex="-1">2. Linear Regression (Trend) <a class="header-anchor" href="#_2-linear-regression-trend" aria-label="Permalink to &quot;2. Linear Regression (Trend)&quot;">​</a></h3><p>Looks at three or more results over time and fits a trend line. If the slope is steep enough and the fit is statistically consistent, it raises a trend alert. This catches slow drifts that would be easy to miss when looking at individual results.</p><p>A trend alert also fires when a marker is approaching the boundary of its reference range — within 15% of the limit — even if it is still technically normal.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Trend detection requires at least three data points for a marker. Import multiple lab results across different dates to get the most value from this feature.</p></div><h2 id="alert-types-and-colors" tabindex="-1">Alert Types and Colors <a class="header-anchor" href="#alert-types-and-colors" aria-label="Permalink to &quot;Alert Types and Colors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Color</th><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td>Orange</td><td>Sudden high / Sudden low</td><td>A large jump in the most recent result</td></tr><tr><td>Red</td><td>Past high / Past low</td><td>A consistent trend already outside range</td></tr><tr><td>Yellow</td><td>Approaching high / Approaching low</td><td>A trend heading toward the boundary</td></tr></tbody></table><p>Sudden change alerts take priority over regression alerts for the same marker.</p><h2 id="critical-flags" tabindex="-1">Critical Flags <a class="header-anchor" href="#critical-flags" aria-label="Permalink to &quot;Critical Flags&quot;">​</a></h2><p>Below the trend alerts, getbased lists <strong>critical flags</strong> — markers where the latest value has crossed more than 50% of the reference range width past the boundary. These are not trend detections; they flag markers that are significantly out of range right now.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Trend alerts and critical flags are informational tools to help you spot patterns. They are not medical diagnoses. Always discuss significant changes with a qualified healthcare provider.</p></div><h2 id="date-range-filter" tabindex="-1">Date Range Filter <a class="header-anchor" href="#date-range-filter" aria-label="Permalink to &quot;Date Range Filter&quot;">​</a></h2><p>All trend detection respects the date range filter set in the header. If you narrow the range to the last six months, only results within that window are analyzed. This is useful for evaluating a specific intervention or health period.</p><p>Markers that appear in trend alerts are excluded from the critical flags section to avoid showing the same marker twice.</p>',20)])])}const g=t(n,[["render",o]]);export{p as __pageData,g as default};
